import React from "react";
import { Routes, Route } from "react-router-dom";
import ProtectedAdminRoute from "../components/product/ProtectedAdminRoute";
import AdminLayout from "../layouts/AdminLayout";

import AdminLogin from "../pages/admin/Login";
import AdminDashboard from "../pages/admin/Dashboard";
import AdminProducts from "../pages/admin/Products";
import AddProduct from "../pages/admin/AddProduct";
import EditProduct from "../pages/admin/EditProduct";
import AdminOrders from "../pages/admin/Orders";
import AdminCategories from "../pages/admin/Categories";
import AdminUsers from "../pages/admin/Users";

import EmailDashboard from "../pages/admin/EmailDashboard";   // NEW
import SendEmailPage from "../pages/admin/SendEmailPage";     // NEW
import EmailTemplates from "../pages/admin/EmailTemplates";   // OPTIONAL
import EmailHistory from "../pages/admin/EmailHistory";       // OPTIONAL

const AdminRoutes = () => {
  return (
    <Routes>
      {/* 🔓 Public route */}
      <Route path="/login" element={<AdminLogin />} />

      {/* 🔐 Protected routes */}
      <Route
        path="/"
        element={
          <ProtectedAdminRoute>
            <AdminLayout />
          </ProtectedAdminRoute>
        }
      >
        <Route path="dashboard" element={<AdminDashboard />} />
        <Route path="products" element={<AdminProducts />} />
        <Route path="products/new" element={<AddProduct />} />
        <Route path="products/edit/:id" element={<EditProduct />} />
        <Route path="orders" element={<AdminOrders />} />
        <Route path="categories" element={<AdminCategories />} />
        <Route path="users" element={<AdminUsers />} />

        {/* 📩 EMAIL SYSTEM */}
        <Route path="email" element={<EmailDashboard />} />         {/* page chính */}
        <Route path="email/send" element={<SendEmailPage />} />      {/* gửi email */}
        <Route path="email/templates" element={<EmailTemplates />} />{/* quản lý template */}
        <Route path="email/history" element={<EmailHistory />} />    {/* lịch sử email */}
      </Route>
    </Routes>
  );
};

export default AdminRoutes;
